// Парсим Telegram message: /start <booking_id>
const msg  = ($json && $json.message) || {};
const from = msg.from || {};
const chat = msg.chat || {};
const rawText = (msg.text || '').toString().trim();

// Разрешённый формат booking_id: A-Z a-z 0-9 - _ , длина 1..80
const BID_RE = /^[A-Za-z0-9_\-]{1,80}$/;
let booking_id = '';
let valid_start = false;
if (/^\/start(\s|$)/.test(rawText)) {
  const parts = rawText.split(/\s+/);
  if (parts.length >= 2) {
    const candidate = parts.slice(1).join(' ').trim();
    if (BID_RE.test(candidate)) {
      booking_id = candidate;
      valid_start = true;
    }
  }
}

return {
  chat_id:          Number(chat.id || 0),
  telegram_user_id: Number(from.id || 0),
  username:         String(from.username || ''),
  first_name:       String(from.first_name || ''),
  last_name:        String(from.last_name || ''),
  text:             rawText,
  booking_id:       booking_id,
  valid_start:      valid_start
};

// Объединяем результат поиска брони с данными /start
const startData = $('Normalize Start').first().json || {};
const bookingRow = ($input.first() && $input.first().json) || null;
const found = !!(bookingRow && bookingRow.id);
return [{ json: {
  ...startData,
  booking_found: found && startData.valid_start,
  booking: found ? {
    id: bookingRow.id,
    apartment_id: String(bookingRow.apartment_id || ''),
    apartment_name: String(bookingRow.apartment_name || ''),
    checkin_at: String(bookingRow.checkin_at || '').slice(0,10),
    checkout_at: String(bookingRow.checkout_at || '').slice(0,10),
    status: String(bookingRow.status || '')
  } : null
} }];

